using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    public required TestContext TestContext { get; init; }

    private readonly PriceCalculator _calculator = new();

    // ──────────────────────────────────────────────
    //  CalculateTotal — DataRow (compile-time constants)
    // ──────────────────────────────────────────────

    [TestMethod]
    [DataRow(10.0, 1, 0.0, 10.0, DisplayName = "Single item, no tax")]
    [DataRow(10.0, 2, 0.1, 22.0, DisplayName = "Two items, 10% tax")]
    [DataRow(0.0, 5, 0.2, 0.0, DisplayName = "Zero unit price")]
    [DataRow(25.0, 0, 0.15, 0.0, DisplayName = "Zero quantity")]
    [DataRow(99.99, 3, 0.0, 299.97, DisplayName = "No tax applied")]
    [DataRow(10.0, 1, 1.0, 20.0, DisplayName = "100% tax rate")]
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // ──────────────────────────────────────────────
    //  CalculateTotal — DynamicData (decimal precision cases)
    // ──────────────────────────────────────────────

    public static IEnumerable<object[]> CalculateTotalPrecisionCases
    {
        get
        {
            yield return [19.99m, 3, 0.08m, 64.7676m, "Fractional tax on fractional price"];
            yield return [0.01m, 1, 0.07m, 0.0107m, "Penny item with tax"];
            yield return [999.99m, 100, 0.25m, 124998.75m, "Large order with 25% tax"];
        }
    }

    [TestMethod]
    [DynamicData(nameof(CalculateTotalPrecisionCases))]
    public void CalculateTotal_PrecisionCases_ReturnsExactDecimal(
        decimal unitPrice, int quantity, decimal taxRate, decimal expected, string scenario)
    {
        TestContext.WriteLine($"Scenario: {scenario}");

        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result);
    }

    // ──────────────────────────────────────────────
    //  CalculateTotal — invalid input validation
    // ──────────────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_NegativeQuantity_ThrowsArgumentOutOfRange()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, -1, 0.1m));

        Assert.AreEqual("quantity", ex.ParamName);
    }

    [TestMethod]
    public void CalculateTotal_NegativeUnitPrice_ThrowsArgumentOutOfRange()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(-5m, 1, 0.1m));

        Assert.AreEqual("unitPrice", ex.ParamName);
    }

    [TestMethod]
